INSERT INTO `features` (`id`, `name`, `name_en`, `type`, `parent_id`, `path`, `order`, `content`, `content_en`, `is_virtual_book`, `virtual_room_type`, `page_type`, `book_cover`, `book_thumbnail`, `created_at`, `updated_at`) VALUES (44, 'Penyusutan Arsip', 'Archive Shrinkage', 'link', 43, '/pengelolaan/penyusutan-arsip', 1, '<div style="max-width:680px; text-align:justify;">\r\n\r\n<div style="display:flex; gap:2%; margin:0 0 20px 0;">\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Foto 1</div>\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Foto 2</div>\r\n</div>\r\n\r\n<p>Penyusutan arsip adalah proses pengurangan jumlah arsip melalui pemindahan arsip inaktif dari unit pengolah ke unit kearsipan, pemusnahan arsip yang tidak memiliki nilai guna, dan penyerahan arsip statis kepada lembaga kearsipan. Penyusutan arsip mencakup kegiatan-kegiatan berikut:</p>\r\n\r\n<!-- NOMOR 1 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>1. Pemindahan arsip inaktif</strong> dari unit pengolah ke unit kearsipan, dilaksanakan melalui tahapan berikut:</p>\r\n<p style="margin:0 0 2px 20px;">a. Pemilahan arsip inaktif;</p>\r\n<p style="margin:0 0 2px 20px;">b. Penataan arsip inaktif; dan</p>\r\n<p style="margin:0 0 0 20px;">c. Pembuatan daftar arsip inaktif.</p>\r\n\r\n<!-- NOMOR 2 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>2. Pemusnahan arsip</strong> yang telah habis masa retensinya dan tidak memiliki nilai guna, dilaksanakan sesuai dengan ketentuan peraturan perundang-undangan, melalui tahapan berikut:</p>\r\n<p style="margin:0 0 2px 20px;">a. Pembentukan Panitia Penilai Arsip;</p>\r\n<p style="margin:0 0 2px 20px;">b. Pemilahan arsip;</p>\r\n<p style="margin:0 0 2px 20px;">c. Pembuatan Daftar Arsip Usul Musnah;</p>\r\n<p style="margin:0 0 2px 20px;">d. Penilaian arsip;</p>\r\n<p style="margin:0 0 2px 20px;">e. Permohonan persetujuan;</p>\r\n<p style="margin:0 0 2px 20px;">f. Penetapan arsip yang akan dimusnahkan; dan</p>\r\n<p style="margin:0 0 0 20px;">g. Pelaksanaan pemusnahan arsip.</p>\r\n\r\n<!-- NOMOR 3 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>3. Penyerahan arsip statis</strong> oleh pencipta arsip kepada lembaga kearsipan, dilaksanakan melalui tahapan berikut:</p>\r\n<p style="margin:0 0 2px 20px;">a. Pemilahan dan pembuatan Daftar Arsip Usul Serah;</p>\r\n<p style="margin:0 0 2px 20px;">b. Penilaian;</p>\r\n<p style="margin:0 0 2px 20px;">c. Pemberitahuan penyerahan arsip statis;</p>\r\n<p style="margin:0 0 2px 20px;">d. Verifikasi dan persetujuan;</p>\r\n<p style="margin:0 0 2px 20px;">e. Penetapan arsip yang akan diserahkan; dan</p>\r\n<p style="margin:0 0 0 20px;">f. Pelaksanaan penyerahan arsip statis.</p>\r\n\r\n</div>', '<div style="max-width:680px; text-align:justify;">\r\n\r\n<div style="display:flex; gap:2%; margin:0 0 20px 0;">\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Photo 1</div>\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Photo 2</div>\r\n</div>\r\n\r\n<p>Archive shrinkage is the process of reducing the number of archives through transferring inactive archives from processing units to archival units, destroying archives that have no use value, and handing over static archives to archival institutions. Archive depreciation includes the following activities:</p>\r\n\r\n<!-- NUMBER 1 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>1. The transfer of inactive archives</strong>from the processing unit to the archives unit, is carried out through the following stages:</p>\r\n<p style="margin:0 0 2px 20px;">a. Inactive archive sorting;</p>\r\n<p style="margin:0 0 2px 20px;">b. Inactive archive setup; and</p>\r\n<p style="margin:0 0 0 20px;">c. Creation of a list of inactive archives.</p>\r\n\r\n<!-- NUMBER 2 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>2. Destruction of archives whose retention period has expired and have no use value is carried out in accordance with statutory provisions, through the following stages:</p>\r\n<p style="margin:0 0 2px 20px;">a. Establishment of an Archives Assessment Committee;</p>\r\n<p style="margin:0 0 2px 20px;">b. Archive sorting;</p>\r\n<p style="margin:0 0 2px 20px;">c. Making a List of Archives of Proposed Destruction;</p>\r\n<p style="margin:0 0 2px 20px;">d. Archive assessment;</p>\r\n<p style="margin:0 0 2px 20px;">e. Request for approval;</p>\r\n<p style="margin:0 0 2px 20px;">f. Determination of archives to be destroyed; and</p>\r\n<p style="margin:0 0 0 20px;">g. Execution of archive destruction.</p>\r\n\r\n<!-- NUMBER 3 -->\r\n<p style="margin-top:24px; margin-bottom:6px;"><strong>3. Submission of static archives</strong>by archive creators to archival institutions, is carried out through the following stages:</p>\r\n<p style="margin:0 0 2px 20px;">a. Sorting and creating a List of Handover Proposal Archives;</p>\r\n<p style="margin:0 0 2px 20px;">b. Assessment;</p>\r\n<p style="margin:0 0 2px 20px;">c. Static archive submission notice;</p>\r\n<p style="margin:0 0 2px 20px;">d. Verification and approval;</p>\r\n<p style="margin:0 0 2px 20px;">e. Determination of archives to be submitted; and</p>\r\n<p style="margin:0 0 0 20px;">f. Implementation of static archive submission.</p>\r\n\r\n</div>', 0, 'none', 'none', NULL, NULL, '2026-04-22 19:38:39', '2026-04-27 01:42:24');
