INSERT INTO `features` (`id`, `name`, `name_en`, `type`, `parent_id`, `path`, `order`, `content`, `content_en`, `is_virtual_book`, `virtual_room_type`, `page_type`, `book_cover`, `book_thumbnail`, `created_at`, `updated_at`) VALUES (49, 'Penjangkauan Arsip', 'Archives Outreach', 'link', 43, '/pengelolaan/penjangkauan-arsip', 6, NULL, NULL, 0, 'none', 'none', NULL, NULL, '2026-04-22 19:46:25', '2026-04-22 19:46:25');
INSERT INTO `features` (`id`, `name`, `name_en`, `type`, `parent_id`, `path`, `order`, `content`, `content_en`, `is_virtual_book`, `virtual_room_type`, `page_type`, `book_cover`, `book_thumbnail`, `created_at`, `updated_at`) VALUES (50, 'Akuisisi Arsip', 'Archive Acquisition', 'link', 43, '/pengelolaan/akuisisi-arsip', 7, NULL, NULL, 0, 'none', 'none', NULL, NULL, '2026-04-22 19:47:00', '2026-04-22 19:47:00');
INSERT INTO `features` (`id`, `name`, `name_en`, `type`, `parent_id`, `path`, `order`, `content`, `content_en`, `is_virtual_book`, `virtual_room_type`, `page_type`, `book_cover`, `book_thumbnail`, `created_at`, `updated_at`) VALUES (51, 'Perpustakaan', 'Library', 'link', 5, '/layanan-publik/perpustakaan', 6, '<div style="max-width:680px; text-align:justify;">\r\n\r\n<p>Layanan Perpustakaan DABB menyediakan bahan pustaka dan referensi untuk mendukung kegiatan kearsipan dan penelitian. Layanan ini memberikan akses kepada pengguna untuk membaca, menelusuri, dan memanfaatkan koleksi yang tersedia sesuai dengan peraturan yang berlaku.</p>\r\n\r\n<h3 style="text-align:left;">Tujuan</h3>\r\n<ol>\r\n  <li>Memberikan akses informasi terkait arsip dan sejarah.</li>\r\n  <li>Mendukung kegiatan penelitian dan penulisan ilmiah.</li>\r\n  <li>Menjadi sumber referensi dalam pengelolaan dan pelestarian arsip.</li>\r\n</ol>\r\n\r\n<p style="text-align:left;">\r\n  <a href="#" style="display:inline-block; background-color:#1565c0; color:#ffffff; padding:12px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;">\r\n    Kunjungi Website Perpustakaan\r\n  </a>\r\n</p>\r\n\r\n<hr style="border:none; border-top:1px solid #e0e0e0; margin:24px 0;">\r\n\r\n<table style="width:100%; border-collapse:collapse;">\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;">\r\n      <strong>Peminjaman Buku</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Lorem Ipsum</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;">\r\n      <strong>Koleksi Digital</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Akses e-book, jurnal ilmiah, dan artikel kapan saja dan di mana saja.</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top;">\r\n      <strong>Ruang Baca dan Belajar</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Ruangan ber-AC yang nyaman dengan WiFi gratis, dilengkapi kursi dan meja untuk belajar individu maupun kelompok.</span>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<hr style="border:none; border-top:1px solid #e0e0e0; margin:24px 0;">\r\n\r\n<h3 style="text-align:left;">Jam Layanan</h3>\r\n<table style="border-collapse:collapse; width:100%; font-size:14px; text-align:left;">\r\n  <tr>\r\n    <td style="padding:5px 0; width:220px;">Senin – Jumat</td>\r\n    <td style="padding:5px 8px; width:16px;">:</td>\r\n    <td style="padding:5px 0;">09.00 – 15.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:5px 0;">Istirahat (Senin – Kamis)</td>\r\n    <td style="padding:5px 8px;">:</td>\r\n    <td style="padding:5px 0;">12.00 – 13.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:5px 0;">(Jumat)</td>\r\n    <td style="padding:5px 8px;">:</td>\r\n    <td style="padding:5px 0;">11.30 – 13.00 WIB</td>\r\n  </tr>\r\n</table>\r\n\r\n<h3 style="text-align:left;">Tata Tertib</h3>\r\n<ol>\r\n  <li>Dilarang membawa makanan dan minuman</li>\r\n  <li>Dilarang merusak buku atau arsip</li>\r\n  <li>Harap menjaga ketenangan</li>\r\n</ol>\r\n\r\n<div style="display:flex; gap:2%; margin:20px 0;">\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Foto 1</div>\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Foto 2</div>\r\n</div>\r\n\r\n<p style="text-align:left;">\r\n  <a href="#" style="display:inline-block; background-color:#1565c0; color:#ffffff; padding:10px 22px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;">\r\n    ⬇ Unduh PDF\r\n  </a>\r\n</p>\r\n\r\n</div>', '<div style="max-width:680px; text-align:justify;">\r\n\r\n<p>DABB Library Services provides library and reference materials to support archival and research activities. This service provides users with access to read, browse and utilize available collections in accordance with applicable regulations.</p>\r\n\r\n<h3 style="text-align:left;">Destination</h3>\r\n<ol>\r\n  <li>Provides access to information related to archives and history.</li>\r\n  <li>Support research and scientific writing activities.</li>\r\n  <li>Become a reference source in archival management and preservation.</li>\r\n</ol>\r\n\r\n<p style="text-align:left;">\r\n  <a href="#" style="display:inline-block; background-color:#1565c0; color:#ffffff; padding:12px 28px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;">\r\n    Visit the Library Website\r\n  </a>\r\n</p>\r\n\r\n<hr style="border:none; border-top:1px solid #e0e0e0; margin:24px 0;">\r\n\r\n<table style="width:100%; border-collapse:collapse;">\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;">\r\n      <strong>Book Lending</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Lorem Ipsum</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top; border-bottom:1px solid #eeeeee;">\r\n      <strong>Digital Collection</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Access e-books, scientific journals and articles anytime and anywhere.</span>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:12px 16px; vertical-align:top; width:56px;">\r\n      <div style="width:48px; height:48px; background-color:#d9d9d9; border-radius:6px;"></div>\r\n    </td>\r\n    <td style="padding:12px 0; vertical-align:top;">\r\n      <strong>Reading and Study Room</strong><br>\r\n      <span style="color:#555555; font-size:14px;">Comfortable air-conditioned room with free WiFi, equipped with chairs and tables for individual and group study.</span>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<hr style="border:none; border-top:1px solid #e0e0e0; margin:24px 0;">\r\n\r\n<h3 style="text-align:left;">Service Hours</h3>\r\n<table style="border-collapse:collapse; width:100%; font-size:14px; text-align:left;">\r\n  <tr>\r\n    <td style="padding:5px 0; width:220px;">Monday – Friday</td>\r\n    <td style="padding:5px 8px; width:16px;">:</td>\r\n    <td style="padding:5px 0;">09.00 – 15.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:5px 0;">Break (Monday – Thursday)</td>\r\n    <td style="padding:5px 8px;">:</td>\r\n    <td style="padding:5px 0;">12.00 – 13.00 WIB</td>\r\n  </tr>\r\n  <tr>\r\n    <td style="padding:5px 0;">(Friday)</td>\r\n    <td style="padding:5px 8px;">:</td>\r\n    <td style="padding:5px 0;">11.30 – 13.00 WIB</td>\r\n  </tr>\r\n</table>\r\n\r\n<h3 style="text-align:left;">Rules</h3>\r\n<ol>\r\n  <li>It is prohibited to bring food and drinks</li>\r\n  <li>Do not damage books or archives</li>\r\n  <li>Please maintain calm</li>\r\n</ol>\r\n\r\n<div style="display:flex; gap:2%; margin:20px 0;">\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Photo 1</div>\r\n  <div style="width:48%; height:220px; background-color:#d9d9d9; border-radius:6px; display:flex; align-items:center; justify-content:center; color:#888888; font-size:13px;">Photo 2</div>\r\n</div>\r\n\r\n<p style="text-align:left;">\r\n  <a href="#" style="display:inline-block; background-color:#1565c0; color:#ffffff; padding:10px 22px; border-radius:5px; text-decoration:none; font-weight:bold; font-size:14px;">\r\n    ⬇ Download PDF\r\n  </a>\r\n</p>\r\n\r\n</div>', 0, 'none', 'none', NULL, NULL, '2026-04-26 20:58:52', '2026-04-27 00:54:48');
INSERT INTO `profiles` (`id`, `feature_id`, `title`, `title_en`, `description`, `description_en`, `type`, `subtitle`, `subtitle_en`, `link_text`, `link_url`, `logo_path`, `chart_data`, `images`, `image_positions`, `order`, `created_at`, `updated_at`) VALUES (1, 41, '', NULL, '<p style="text-align: justify;"><span style="font-weight: 700; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; font-size: 16px;">TUGAS</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style="text-align: justify;"><span style="font-size: 14px;">Depot Arsip Berkelanjutan ANRI di Provinsi Jawa Barat mempunyai tugas melaksanakan penyelamatan, pengolahan, pelestarian dan pelindungan serta layanan dan pemanfaatan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style="text-align: justify;"><span style="font-weight: bold; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; font-size: 16px;">FUNGSI</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role="list"><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">Pelaksanaan koordinasi dengan unit kerja Arsip Nasional Republik Indonesia dan instansi terkait dalam rangka melaksanakan tugas dan fungsinya;</span></li><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">pelaksanaan penyelamatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">pelaksanaan pengolahan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">pelaksanaan pelestarian dan pelindungan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat; dan</span></li><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">pelaksanaan layanan dan pemanfaatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style="text-align: justify; color: rgb(0, 204, 255);"><a href="https://kearsipan.undip.ac.id/download/" target="_blank" style="color: rgb(0, 204, 255); font-size: 14px; font-weight: bold;">Unduh Undang-Undang No. 43 Tahun 2009 tentang Kearsipan dan Peraturan Pemerintah No. 28 Tahun 2012 Tentang Pelaksanaan.</a></div>', '<p style="text-align: justify;"><span style="font-weight: 700; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; 16px;">TASK</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style="text-align: justify;"><span style="font-size: 14px;">The ANRI Sustainable Archives Depot in West Java Province has the task of carrying out the rescue, processing, preservation and protection as well as services and utilization of static archives of central state institutions in the West Java Province region.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style="text-align: justify;"><span style="font-weight: bold; text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration:underline;text-decoration-line:underline; 16px;">FUNCTION</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role="list"><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">Implementation of coordination with the work unit of the National Archives of the Republic of Indonesia and related agencies in order to carry out their duties and functions; and static archives of central level state institutions in West Java Province; 14px;">implementation of preservation and protection of inactive archives that have sustainable value and static archives of central state institutions in the West Java Province region; and</span></li><li style="text-align: justify; white-space: pre-wrap;"><span style="font-size: 14px;">implementation of services and utilization of inactive archives that have ongoing value and static archives of central state institutions in the West Java Province region.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style="text-align: justify; color: rgb(0, 204, 255);"><a href="https://kearsipan.undip.ac.id/download/" target="_blank" style="color: rgb(0, 204, 255); font-size: 14px; font-weight: bold;">Download Law no. 43 of 2009 concerning Archives and Government Regulation no. 28 of 2012 concerning Implementation.</a></div>', 'tugas_fungsi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2, '2026-04-09 20:00:50', '2026-04-15 19:59:42');
INSERT INTO `profiles` (`id`, `feature_id`, `title`, `title_en`, `description`, `description_en`, `type`, `subtitle`, `subtitle_en`, `link_text`, `link_url`, `logo_path`, `chart_data`, `images`, `image_positions`, `order`, `created_at`, `updated_at`) VALUES (2, 41, '', NULL, '<p>\r\n</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify"><span style=" font-weight: 700; text-decoration: underline; font-size: 16px">TUGAS</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify"><span style=" font-size: 14px">Depot Arsip Berkelanjutan ANRI di Provinsi Jawa Barat mempunyai tugas melaksanakan penyelamatan, pengolahan, pelestarian dan pelindungan serta layanan dan pemanfaatan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify"><span style=" font-weight: bold; text-decoration: underline; font-size: 16px">FUNGSI</span><br /></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ol role="list" style=" margin: 1em 0px; padding-left: 1.5rem; list-style-type: decimal"><li style=" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap"><span style=" font-size: 14px">Pelaksanaan koordinasi dengan unit kerja Arsip Nasional Republik Indonesia dan instansi terkait dalam rangka melaksanakan tugas dan fungsinya;</span></li><li style=" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap"><span style=" font-size: 14px">pelaksanaan penyelamatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap"><span style=" font-size: 14px">pelaksanaan pengolahan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat;</span></li><li style=" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap"><span style=" font-size: 14px">pelaksanaan pelestarian dan pelindungan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat; dan</span></li><li style=" margin: 0.25em 0px; text-align: justify; white-space: pre-wrap"><span style=" font-size: 14px">pelaksanaan layanan dan pemanfaatan arsip inaktif yang memiliki nilai berkelanjutan dan arsip statis lembaga negara tingkat pusat di wilayah Provinsi Jawa Barat.</span></li></ol>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<div style=" color: rgb(0, 204, 255); font-size: 1rem; line-height: 1.75; text-align: justify"><a href="https://kearsipan.undip.ac.id/download/" target="_blank" style=" color: rgb(0, 204, 255); text-decoration: none; transition: color 0.2s; font-size: 14px; font-weight: bold">Unduh Undang-Undang No. 43 Tahun 2009 tentang Kearsipan dan Peraturan Pemerintah No. 28 Tahun 2012 Tentang Pelaksanaan.</a></div>', '<p>\r\n</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify"><span style=" font-weight: 700; text-decoration: underline; font-size: 16px">TASK</span></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<p style=" color: rgb(71, 85, 105); font-size: 1rem; line-height: 1.75; margin-bottom: 1rem; text-align: justify"><span style=" font-size: 14px">The ANRI Sustainable Archives Depot in West Java Province has the tas