INSERT INTO `virtual_book_pages` (`id`, `feature_id`, `title`, `title_en`, `content`, `content_en`, `image`, `images`, `image_positions`, `text_position`, `thumbnail`, `image_height`, `image_fit_mode`, `page_number`, `is_cover`, `is_back_cover`, `order`, `created_at`, `updated_at`, `book_id`) VALUES (9, 26, 'Slide 6', 'Slide 6', NULL, NULL, NULL, '["features/virtual-books/K2BZzRbO5Ef8OQLuVvbFyU9Q3g3B34OHovhX1fIZ.png"]', '[{"x": 0, "y": 0}]', '{"x": 0, "y": 0, "width": 45, "height": 30}', 'features/virtual-books/thumbnails/page_thumb_1776872331_69e8eb8b34d20.png', 100, 'fullbleed', 0, 0, 0, 6, '2026-04-22 08:38:51', '2026-04-22 08:38:51', 8);
INSERT INTO `virtual_book_pages` (`id`, `feature_id`, `title`, `title_en`, `content`, `content_en`, `image`, `images`, `image_positions`, `text_position`, `thumbnail`, `image_height`, `image_fit_mode`, `page_number`, `is_cover`, `is_back_cover`, `order`, `created_at`, `updated_at`, `book_id`) VALUES (10, 26, 'Proklamasi Kemerdekaan (1945)', 'Proclamation of Independence (1945)', 'Pada 17 Agustus 1945, Soekarno dan Hatta membacakan teks proklamasi di Jakarta. Peristiwa ini menandai lahirnya Republik Indonesia.', 'On August 17 1945, Soekarno and Hatta read the text of the proclamation in Jakarta. This event marked the birth of the Republic of Indonesia.', NULL, '["features/virtual-books/giV9XOlkx3FSBp0MkrUzQgXs4uscIFpHIpCzK8z2.jpg"]', '[{"x": "11.985187989285754", "y": "2.666666395399333"}]', '{"x": "0", "y": "57.66110660185683", "width": "100", "height": "29.3334"}', 'features/virtual-books/thumbnails/page_thumb_1776872866_69e8eda254f42.png', 75, 'contained', 0, 0, 0, 1, '2026-04-22 08:47:46', '2026-04-22 08:47:46', 7);
INSERT INTO `virtual_book_pages` (`id`, `feature_id`, `title`, `title_en`, `content`, `content_en`, `image`, `images`, `image_positions`, `text_position`, `thumbnail`, `image_height`, `image_fit_mode`, `page_number`, `is_cover`, `is_back_cover`, `order`, `created_at`, `updated_at`, `book_id`) VALUES (11, 26, 'Kerajaan Majapahit (1293–1500)', 'Majapahit Kingdom (1293–1500)', 'Majapahit adalah kerajaan besar di Jawa Timur yang mencapai puncak kejayaan di bawah Hayam Wuruk dan Gajah Mada.', 'Majapahit was a large kingdom in East Java that reached the peak of glory under Hayam Wuruk and Gajah Mada.', NULL, '["features/virtual-books/0Naee2gDQ8Hsr2k8QZQIEfvgXKT3Ea8WFKZOEprh.webp"]', '[{"x": 8.104166666666666, "y": 0}]', '{"x": "3.111111111111111", "y": "51.33333333333333", "width": "94.3333", "height": "36.3333"}', 'features/virtual-books/thumbnails/page_thumb_1776874205_69e8f2ddc7fe4.png', 84, 'contained', 0, 0, 0, 2, '2026-04-22 09:06:34', '2026-04-22 09:10:05', 7);
INSERT INTO `virtual_book_pages` (`id`, `feature_id`, `title`, `title_en`, `content`, `content_en`, `image`, `images`, `image_positions`, `text_position`, `thumbnail`, `image_height`, `image_fit_mode`, `page_number`, `is_cover`, `is_back_cover`, `order`, `created_at`, `updated_at`, `book_id`) VALUES (12, 26, 'Kolonialisme Belanda', 'Dutch Colonialism', 'Belanda mulai menguasai Nusantara sejak abad ke-17 melalui VOC. Sistem tanam paksa dan eksploitasi sumber daya menyebabkan penderitaan rakyat.', 'The Dutch began to control the archipelago in the 17th century through the VOC. The system of forced cultivation and exploitation of resources causes suffering to the people.', NULL, '["features/virtual-books/f2NXFhjaq0t0ejjLjG4JZclTuJ3JbCHvEUFdcZOf.jpg"]', '[{"x": "12.444444444444445", "y": "0"}]', '{"x": "0", "y": "49.666666666666664", "width": "100", "height": "32.6667"}', 'features/virtual-books/thumbnails/page_thumb_1776874361_69e8f379499d2.png', 74, 'contained', 0, 0, 0, 3, '2026-04-22 09:12:41', '2026-04-22 09:12:41', 7);
INSERT INTO `virtual_book_pages` (`id`, `feature_id`, `title`, `title_en`, `content`, `content_en`, `image`, `images`, `image_positions`, `text_position`, `thumbnail`, `image_height`, `image_fit_mode`, `page_number`, `is_cover`, `is_back_cover`, `order`, `created_at`, `updated_at`, `book_id`) VALUES (13, 26, 'Pergerakan Nasional (1908–1945)', 'National Movement (1908–1945)', 'Dimulai dengan berdirinya Budi Utomo (1908), pergerakan nasional melahirkan organisasi seperti Sarekat Islam dan PNI. Sumpah Pemuda 1928 menjadi simbol persatuan bangsa.', 'Starting with the founding of Budi Utomo (1908), the national movement gave birth to organizations such as Sarekat Islam and PNI. The 1928 Youth Pledge became a symbol of national unity.', NULL, '["features/virtual-books/P5ymgYPAb4le50bUDiO8FMjpUa7y7XmztThZMvU5.webp"]', '[{"x": "5.333333333333334", "y": "0"}]', '{"x": "0.8888888888888888", "y": "57.99999999999999", "width": "100", "height": "32.3333"}', 'features/virtual-books/thumbnails/page_thumb_1776874732_69e8f4ec339f2.png', 90, 'contained', 0, 0, 0, 4, '2026-04-22 09:18:52', '2026-04-22 09:18:52', 7);
